import React, { useState, useEffect } from 'react';
import { cropAPI } from '../api';

const SEASONS = ['', 'kharif', 'rabi', 'zaid'];
const SOILS = ['', 'black', 'red', 'loamy', 'sandy', 'alluvial'];
const STATES = ['', 'Telangana', 'Andhra Pradesh', 'Maharashtra', 'Karnataka', 'Tamil Nadu', 'Madhya Pradesh', 'Uttar Pradesh', 'Punjab'];

export default function CropRecommendation() {
  const [filters, setFilters] = useState({ soil: '', season: '', state: '' });
  const [crops, setCrops] = useState([]);
  const [loading, setLoading] = useState(false);
  const [diseases, setDiseases] = useState(null);
  const [selectedCrop, setSelectedCrop] = useState(null);

  useEffect(() => { fetchCrops(); }, []);

  const fetchCrops = async () => {
    setLoading(true);
    try {
      const res = await cropAPI.recommend(filters);
      setCrops(res.data.recommendations || []);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const fetchDiseases = async (crop) => {
    setSelectedCrop(crop);
    try {
      const res = await cropAPI.diseases(crop.name.split('/')[0].trim().toLowerCase());
      setDiseases(res.data.diseases || []);
    } catch (e) { setDiseases([]); }
  };

  return (
    <div style={styles.container}>
      {/* Filters */}
      <div style={styles.filterCard}>
        <div style={styles.filterTitle}>🌱 Find Best Crops for Your Farm</div>
        <div style={styles.filterRow}>
          <div className="form-group" style={{ flex: 1, marginBottom: 0 }}>
            <label>Season</label>
            <select value={filters.season} onChange={(e) => setFilters(p => ({...p, season: e.target.value}))}>
              {SEASONS.map(s => <option key={s} value={s}>{s || 'All Seasons'}</option>)}
            </select>
          </div>
          <div className="form-group" style={{ flex: 1, marginBottom: 0 }}>
            <label>Soil Type</label>
            <select value={filters.soil} onChange={(e) => setFilters(p => ({...p, soil: e.target.value}))}>
              {SOILS.map(s => <option key={s} value={s}>{s || 'All Soil Types'}</option>)}
            </select>
          </div>
          <div className="form-group" style={{ flex: 1, marginBottom: 0 }}>
            <label>State</label>
            <select value={filters.state} onChange={(e) => setFilters(p => ({...p, state: e.target.value}))}>
              {STATES.map(s => <option key={s} value={s}>{s || 'All States'}</option>)}
            </select>
          </div>
          <button className="btn btn-primary" onClick={fetchCrops} disabled={loading} style={{ alignSelf: 'flex-end', height: 42 }}>
            {loading ? <span className="spinner" style={{width:16,height:16}} /> : '🔍 Get Recommendations'}
          </button>
        </div>
      </div>

      {/* Crop Cards */}
      <div style={styles.cropsGrid}>
        {loading ? (
          <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: 40 }}>
            <div className="spinner" style={{width:40,height:40,margin:'0 auto'}} />
          </div>
        ) : crops.map((crop, i) => (
          <div key={i} style={styles.cropCard}>
            <div style={{ ...styles.cropHeader, background: crop.color + '22', borderBottom: `3px solid ${crop.color}` }}>
              <span style={styles.cropIcon}>{crop.icon}</span>
              <div>
                <div style={styles.cropName}>{crop.name}</div>
                <div style={styles.cropDuration}>⏱️ {crop.duration}</div>
              </div>
              <div style={{ ...styles.yieldBadge, background: crop.color, color: 'white' }}>
                {crop.expectedYield}
              </div>
            </div>
            <div style={styles.cropBody}>
              <div style={styles.cropDesc}>{crop.description}</div>
              <button
                className="btn btn-outline"
                style={{ width: '100%', justifyContent: 'center', fontSize: '0.82rem', marginTop: 12 }}
                onClick={() => fetchDiseases(crop)}
              >
                🔬 View Disease Info
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Disease Modal */}
      {diseases && selectedCrop && (
        <div style={styles.modal}>
          <div style={styles.modalBox}>
            <div style={styles.modalHeader}>
              <div style={styles.modalTitle}>{selectedCrop.icon} {selectedCrop.name} — Disease Guide</div>
              <button onClick={() => setDiseases(null)} style={styles.closeBtn}>✕</button>
            </div>
            {diseases.map((d, i) => (
              <div key={i} style={styles.diseaseItem}>
                <div style={styles.diseaseName}>🦠 {d.name}</div>
                <div style={styles.diseaseRow}><span style={styles.diseaseLabel}>Symptoms:</span> {d.symptoms}</div>
                <div style={styles.diseaseRow}><span style={styles.diseaseLabel}>Treatment:</span> {d.treatment}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { display: 'flex', flexDirection: 'column', gap: 20 },
  filterCard: { background: 'white', borderRadius: 16, padding: '20px 24px', border: '1px solid #C8E6C9' },
  filterTitle: { fontFamily: "'Nunito', sans-serif", fontWeight: 800, color: '#1B5E20', marginBottom: 16 },
  filterRow: { display: 'flex', gap: 14, alignItems: 'flex-end', flexWrap: 'wrap' },
  cropsGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: 16 },
  cropCard: { background: 'white', borderRadius: 14, overflow: 'hidden', border: '1px solid #C8E6C9', boxShadow: '0 2px 8px rgba(46,125,50,0.06)' },
  cropHeader: { display: 'flex', alignItems: 'center', gap: 12, padding: '14px 16px' },
  cropIcon: { fontSize: 32, flexShrink: 0 },
  cropName: { fontWeight: 700, fontSize: '0.95rem', color: '#1B2B1A' },
  cropDuration: { fontSize: '0.78rem', color: '#5D7A5C', marginTop: 2 },
  yieldBadge: { marginLeft: 'auto', padding: '4px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 700, flexShrink: 0 },
  cropBody: { padding: '12px 16px' },
  cropDesc: { fontSize: '0.83rem', color: '#5D7A5C', lineHeight: 1.5 },
  modal: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 20 },
  modalBox: { background: 'white', borderRadius: 16, padding: 28, maxWidth: 540, width: '100%', maxHeight: '80vh', overflowY: 'auto' },
  modalHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 },
  modalTitle: { fontFamily: "'Nunito', sans-serif", fontWeight: 800, color: '#1B5E20', fontSize: '1.1rem' },
  closeBtn: { background: 'none', border: 'none', fontSize: '1.2rem', cursor: 'pointer', color: '#5D7A5C' },
  diseaseItem: { border: '1px solid #C8E6C9', borderRadius: 10, padding: 14, marginBottom: 12 },
  diseaseName: { fontWeight: 700, color: '#C62828', marginBottom: 8 },
  diseaseRow: { fontSize: '0.85rem', color: '#5D7A5C', marginBottom: 4 },
  diseaseLabel: { fontWeight: 700, color: '#1B2B1A' },
};
